const items = $input.all();

const doctorData = {};

for (const item of items) {
  const doctorName = item.json.doctor_name;
  const slotDate = item.json.slot_date;
  const key = `${doctorName}-${slotDate}`;

  if (!doctorData[key]) {
    doctorData[key] = {
      doctor_name: doctorName,
      slot_date: slotDate,
      slots: [],
    };
  }

  doctorData[key].slots.push({
    schedule_id: item.json.schedule_id,
    start_time: item.json.slot_start_time,
    end_time: item.json.slot_end_time,
  });
}

return [
  {
    json: {
      consolidated_data: Object.values(doctorData),
    },
  },
];

