const data = $json.body.args;

const errors = [];

if (!data.email || !data.email.includes("@")) {
  errors.push("Invalid email address");
}

if (!data.phone_no || data.phone_no.length < 10) {
  errors.push("Invalid phone number");
}

if (!data.schedule_id) {
  errors.push("Missing schedule ID");
}

if (errors.length > 0) {
  return [
    {
      json: {
        valid: false,
        errors: errors
      }
    }
  ];
}

return [
  {
    json: {
      valid: true,
      data: data
    }
  }
];

