const items = $input.all();

if (items.length === 0) {
  return [
    {
      json: {
        message: "Sorry, I couldn't find a complaint with that ID. Please check the number and try again."
      }
    }
  ];
}

const outputItems = [];

for (const item of items) {

  const complaintCode = item.json.complaint_code || "Unknown";
  const name = item.json.name || "Customer";
  const status = (item.json.status || "").toLowerCase();
  const createdAt = item.json.created_at ? new Date(item.json.created_at) : null;

  const now = new Date();
  let diffHours = 0;

  if (createdAt) {
    diffHours = (now - createdAt) / (1000 * 60 * 60);
  }

  let message = "";
  let escalate = false;

  if (status === "pending" && diffHours > 48) {

    escalate = true;
    message = `${name}, your complaint ${complaintCode} has been pending for longer than expected. I will escalate it to our support team immediately.`;

  } 
  else if (status === "resolved") {

    message = `${name}, your complaint ${complaintCode} has been resolved. Thank you for your patience!`;

  } 
  else if (status === "pending") {

    message = `${name}, your complaint ${complaintCode} is currently pending. Our team is working on it.`;

  } 
  else if (status === "in_progress") {

    message = `${name}, your complaint ${complaintCode} is currently being worked on by our team.`;

  } 
  else {

    message = `${name}, the current status of complaint ${complaintCode} is ${status || "unknown"}.`;

  }

  outputItems.push({
    json: {
      complaint_code: complaintCode,
      name: name,
      status: status,
      escalate: escalate,
      message: message
    }
  });
}

return outputItems;
